// NQxb_Artifact_Promote_v1__Normalize_request
// Purpose: Validate promote request shape, enforce required fields,
//          normalize selector, generate request_id.
// T87: Enhanced validation hints for developer ergonomics.

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = (Math.random() * 16) | 0;
    const v = (c === 'x') ? r : ((r & 0x3) | 0x8);
    return v.toString(16);
  });
}

const j = $json ?? {};

const gw_action = j.gw_action ?? "artifact.promote";
const gw_workspace_id = j.gw_workspace_id ?? j.workspace_id ?? null;
const artifact_type = j.artifact_type ?? null;
const artifact_id = j.artifact_id ?? null;

const transition_raw = j.artifact_payload?.transition ?? null;
const reason_raw = j.artifact_payload?.reason ?? null;

const actor_user_id_raw = j.actor_user_id ?? null;

const selector_in = (j.selector && typeof j.selector === "object") ? j.selector : {};
const hydrate = selector_in.hydrate === true;

const transition =
  (typeof transition_raw === "string") ? transition_raw.trim() : "";

const reason =
  (typeof reason_raw === "string") ? reason_raw.trim() : "";

const actor_user_id =
  (typeof actor_user_id_raw === "string" && actor_user_id_raw.trim().length > 0)
    ? actor_user_id_raw.trim()
    : null;

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

const fail = (code, message, details = {}) => [{
  json: {
    ok: false,
    _gw_route: "error",
    gw_action: "artifact.promote",
    gw_workspace_id,
    artifact_type,
    artifact_id,
    error: { code, message, details },
    timestamp: new Date().toISOString(),
  },
}];

// ---- Validation ----
if (!gw_workspace_id) {
  return fail("VALIDATION_ERROR", "gw_workspace_id is required", {
    hint: "Include gw_workspace_id in the promote request.",
  });
}
if (!artifact_type) {
  return fail("VALIDATION_ERROR", "artifact_type is required", {
    hint: "Include artifact_type (e.g., \"project\") in the promote request.",
  });
}
if (!artifact_id) {
  return fail("VALIDATION_ERROR", "artifact_id is required", {
    hint: "Include the UUID of the artifact to promote.",
  });
}
if (!transition) {
  return fail("VALIDATION_ERROR", "transition is required", {
    source: "artifact_payload.transition",
    allowed_transitions: ["seed_to_sapling", "sapling_to_tree", "tree_to_archive"],
    hint: "Include transition in your payload: { \"transition\": \"seed_to_sapling\", \"reason\": \"...\" }",
  });
}
if (!reason || reason.length < 1 || reason.length > 280) {
  return fail("VALIDATION_ERROR", "reason is required (1..280 chars)", {
    received_length: reason.length,
    hint: "Provide a reason string between 1 and 280 characters explaining why this promotion is happening.",
  });
}
if (actor_user_id && !UUID_RE.test(actor_user_id)) {
  return fail("VALIDATION_ERROR", "actor_user_id must be a valid UUID when provided", {
    actor_user_id,
  });
}

const request_id = uuidv4();

return [{
  json: {
    ok: true,
    gw_action: "artifact.promote",
    gw_workspace_id,
    artifact_type: String(artifact_type),
    artifact_id: String(artifact_id),
    transition,
    reason,
    selector: { hydrate },
    request_id,
    actor_user_id,
  },
}];

// NQxb_Artifact_Promote_v1__Resolve_Transition
// Purpose: Map a locked transition allow-list -> from_state/to_state, or reject.
// T87: Enhanced error hint.
//
// QPM PHASE 2: Only forward transitions allowed (archive is terminal).

const input = $json;

const transition = (
  input.transition ??
  input.artifact_payload?.transition ??
  ""
).toString().trim();

const map = {
  seed_to_sapling: { from_state: "seed", to_state: "sapling" },
  sapling_to_tree: { from_state: "sapling", to_state: "tree" },
  tree_to_archive: { from_state: "tree", to_state: "archive" },
};

const resolved = map[transition];

if (!resolved) {
  return [
    {
      json: {
        ...input,
        ok: false,
        _gw_route: "error",
        error: {
          code: "LIFECYCLE_TRANSITION_NOT_ALLOWED",
          message: `Transition not allowed: '${transition || "(empty)"}'`,
          details: {
            transition: transition || null,
            allowed: Object.keys(map),
            hint: "Transitions follow the pattern: seed_to_sapling, sapling_to_tree, tree_to_archive. Archive is terminal (irreversible).",
          },
        },
      },
    },
  ];
}

return [
  {
    json: {
      ...input,
      ok: true,
      _gw_route: input._gw_route ?? "ok",
      from_state: resolved.from_state,
      to_state: resolved.to_state,
    },
  },
];

// NQxb_Artifact_Promote_v1__Enforce_Verified_State
// Purpose: Ensure artifact exists, is not deleted, and lifecycle_status matches from_state.
// T87: deleted_at guard + enriched lifecycle mismatch with allowed_transitions + hints.
//
// QPM PHASE 2: Captures spine.summary for QPM validation downstream.

const input = $json;

// Short-circuit: if Resolve_Transition already errored, pass through its error (C01 fix)
const resolveOutput = $node["NQxb_Artifact_Promote_v1__Resolve_Transition"]?.json ?? {};
if (resolveOutput.ok === false && resolveOutput._gw_route === "error" && resolveOutput.error) {
  return [{ json: resolveOutput }];
}

// --- Required fields from merged input ---
const artifactId = input.artifact_id ?? null;
const fromState = (input.from_state ?? "").toString().trim();

// --- Pull VERIFIED state directly from Verify_Current_State ---
const verifiedNode = $node["NQxb_Artifact_Promote_v1__Verify_Current_State"];
const verifiedRaw = verifiedNode?.json ?? null;

// Supabase "get" may return object OR array
const verified = Array.isArray(verifiedRaw)
  ? verifiedRaw[0] ?? null
  : verifiedRaw;

const actual = verified?.lifecycle_status ?? null;
const summary = verified?.summary ?? null;

// --- Guards ---

if (!artifactId) {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "ARTIFACT_NOT_FOUND",
        message: "artifact_id missing after DB verify.",
        details: { artifact_id: null }
      }
    }
  }];
}

// T87: deleted_at guard — prevent promoting soft-deleted artifacts
if (verified && verified.deleted_at) {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "NOT_FOUND",
        message: "Artifact not found or has been deleted.",
        details: {
          artifact_id: artifactId,
          hint: "This artifact has been soft-deleted. Use artifact.restore before promoting."
        }
      }
    }
  }];
}

if (!fromState) {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "FROM_STATE_MISSING",
        message: "from_state missing after Resolve_Transition.",
        details: { from_state: input.from_state ?? null }
      }
    }
  }];
}

if (!actual) {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "NOT_FOUND",
        message: "Artifact not found or has been deleted.",
        details: {
          artifact_id: artifactId,
          hint: "Verify the artifact_id exists and has not been soft-deleted. Use artifact.restore to recover deleted artifacts."
        }
      }
    }
  }];
}

// --- Enforce pre-update lifecycle correctness ---

if (actual !== fromState) {
  const transitionMap = {
    seed: ["seed_to_sapling"],
    sapling: ["sapling_to_tree"],
    tree: ["tree_to_archive"],
    archive: [],
  };
  const allowedFromCurrent = transitionMap[actual] ?? [];

  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "LIFECYCLE_STATE_MISMATCH",
        message: `Cannot apply transition '${input.transition ?? "unknown"}': artifact is currently '${actual}', but transition requires '${fromState}'.`,
        details: {
          artifact_id: artifactId,
          requested_transition: input.transition ?? null,
          expected_from_state: fromState,
          actual_lifecycle_status: actual,
          allowed_transitions_from_current: allowedFromCurrent,
          hint: allowedFromCurrent.length > 0
            ? `Artifact is '${actual}'. Valid transition(s): ${allowedFromCurrent.join(", ")}.`
            : `Artifact is '${actual}'. No further promotions available (terminal state).`
        }
      }
    }
  }];
}

// --- Success: verified correctly ---
return [{
  json: {
    ...input,
    ok: true,
    _gw_route: input._gw_route ?? "ok",
    _spine_summary: summary,
    _lifecycle_verify: {
      artifact_id: artifactId,
      verified_from_state: fromState,
      current_lifecycle_status: actual
    }
  }
}];

// NQxb_Artifact_Promote_v1__Compute_Next_Version
// v23 NEW NODE (2026-02-25)
// Purpose: Derive version exclusively from verified DB state.
// Do NOT rely on $json.version passed from request.
// Source of truth: Verify_Current_State (Supabase GET result).
//
// Outputs:
//   verified_version   — current version from DB
//   next_version        — verified_version + 1
//   verified_lifecycle_status — lifecycle from DB (belt-and-suspenders)

const input = $json;

const verifiedNode = $node["NQxb_Artifact_Promote_v1__Verify_Current_State"];
const verifiedRaw = verifiedNode?.json ?? null;

// Supabase GET may return object OR array
const verified = Array.isArray(verifiedRaw)
  ? verifiedRaw[0] ?? null
  : verifiedRaw;

const currentVersion = verified?.version ?? null;

if (typeof currentVersion !== 'number' || !Number.isFinite(currentVersion) || currentVersion < 1) {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "VERSION_UNAVAILABLE",
        message: "Could not determine current version from verified DB state.",
        details: {
          artifact_id: input.artifact_id ?? null,
          raw_version: currentVersion
        }
      }
    }
  }];
}

return [{
  json: {
    ...input,
    verified_version: currentVersion,
    next_version: currentVersion + 1,
    verified_lifecycle_status: verified?.lifecycle_status ?? null
  }
}];

// NQxb_Artifact_Promote_v1__Check_Concurrency
// v23 NEW NODE (2026-02-25)
// Purpose: Detect zero-row update (optimistic concurrency failure).
// Supabase UPDATE returns the updated row on match, empty {} on no match.
// With alwaysOutputData: true, zero rows = one item with empty $json.
//
// On success: pass through promote context from Compute_Next_Version.
// On failure: structured CONCURRENCY_CONFLICT error envelope.

const dbResult = $json;
const promoteContext = $node["NQxb_Artifact_Promote_v1__Compute_Next_Version"].json;

// Supabase UPDATE with version filter returns the updated row if matched.
// If version didn't match, result is empty (no artifact_id field).
if (!dbResult.artifact_id) {
  return [{
    json: {
      ok: false,
      _gw_route: "error",
      gw_action: "artifact.promote",
      gw_workspace_id: promoteContext.gw_workspace_id ?? null,
      artifact_type: promoteContext.artifact_type ?? null,
      artifact_id: promoteContext.artifact_id ?? null,
      error: {
        code: "CONCURRENCY_CONFLICT",
        message: "Artifact version mismatch during promote",
        details: {
          artifact_id: promoteContext.artifact_id ?? null,
          expected_version: promoteContext.verified_version ?? null
        }
      }
    }
  }];
}

// Success — pass through promote context for downstream event/response shaping
return [{
  json: {
    ...promoteContext,
    ok: true,
    _db_update_confirmed: true
  }
}];

