// NQxb_Artifact_Promote_v1__Pass_Actor
const input = $json;

return [{
  json: {
    ...input,
    actor_user_id: input.actor_user_id ?? null
  }
}];

// NQxb_Artifact_Promote_v1__Freeze_Event_Payload
// HARDENING FIX (2026-02-22): Use $node[] reference instead of $json.
// After serialization, DB_Update_Lifecycle runs before this node,
// so $json would be the Supabase row, not the promote context.
const j = $node["NQxb_Artifact_Promote_v1__QPM_Validate_Rules"].json ?? {};

return [{
  json: {
    ...j,
    _event_payload: {
      request_id: j.request_id ?? null,
      transition: j.transition ?? null,
      from_state: j.from_state ?? null,
      to_state: j.to_state ?? null,
      reason: j.reason ?? null,
      artifact_type: j.artifact_type ?? null,
      gw_action: j.gw_action ?? null,
    }
  }
}];

// Type_Registry_Guard — Check artifact type against qxb_artifact_type_registry
// FAIL-CLOSED: No row found = not_registered; enabled=false = disabled
// T87: Enhanced error hints for promotion context.

const originalRequest = $node['Pass_Actor'].json;
const registryRow = $json;
const artifact_type = originalRequest.artifact_type;

if (!registryRow || !registryRow.artifact_type) {
  return [{
    json: {
      ok: false,
      _gw_route: 'error',
      gw_action: originalRequest.gw_action,
      gw_workspace_id: originalRequest.gw_workspace_id,
      artifact_type: artifact_type,
      error: {
        code: 'ARTIFACT_TYPE_NOT_ALLOWED',
        message: `Artifact type '${artifact_type}' is not allowed`,
        details: {
          artifact_type: artifact_type,
          reason: 'not_registered',
          hint: 'Only registered artifact types can be promoted. Currently only "project" supports lifecycle promotion.'
        }
      }
    }
  }];
}

if (registryRow.enabled === false) {
  return [{
    json: {
      ok: false,
      _gw_route: 'error',
      gw_action: originalRequest.gw_action,
      gw_workspace_id: originalRequest.gw_workspace_id,
      artifact_type: artifact_type,
      error: {
        code: 'ARTIFACT_TYPE_NOT_ALLOWED',
        message: `Artifact type '${artifact_type}' is not allowed`,
        details: {
          artifact_type: artifact_type,
          reason: 'disabled',
          registry_enabled: false,
          hint: 'This artifact type exists in the registry but is currently disabled.'
        }
      }
    }
  }];
}

return [{ json: originalRequest }];

// NQxb_Artifact_Promote_v1__Shape_Response
// Canonical success envelope wrapper for artifact.promote
//
// HARD RULES:
// - Do NOT change promote business logic or DB writes.
// - Do NOT assume any optional node executed unless guarded.
// - Must be safe even if invoked on error paths.
//
// Expected final envelope:
//
// {
//   "ok": true,
//   "gw_action": "artifact.promote",
//   "workspace_id": "...",
//   "artifact_type": "project",
//   "artifact_id": "...",
//   "event_id": "...",
//   "operation": "PROMOTE",
//   "from_state": "...",
//   "to_state": "...",
//   "transition": "...",
//   "timestamp": "...",
//   "data": { "event": { ... } }
// }

const input = $json ?? {};

// 1) Pass through error envelopes unchanged
if (input.ok === false || input._gw_route === "error") {
  return [{ json: input }];
}

// 2) Identify the "event" object to wrap.
// In the fixed wiring, this node should receive the inserted event row from DB_Insert_Event.
// Still, we handle alternate shapes defensively.
let event = null;

// If input already looks like the event row
if (input.event_id && input.workspace_id && input.artifact_id) {
  event = input;
} else {
  // Try to read from DB_Insert_Event directly (best-effort)
  try {
    const evNode = $node["NQxb_Artifact_Promote_v1__DB_Insert_Event"];
    const evJson = evNode?.json ?? null;
    if (evJson && evJson.event_id) event = evJson;
  } catch (e) {
    event = null;
  }
}

// If we still don't have an event, fail closed with a stable INTERNAL_ERROR envelope
if (!event) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: {
          code: "INTERNAL_ERROR",
          message: "Promote succeeded but event payload was unavailable for response shaping.",
          details: { reason: "missing_event_row" },
        },
      },
    },
  ];
}

// 3) Pull promote context from the event payload (authoritative for from/to/transition)
const payload = event.payload ?? {};
const from_state = payload.from_state ?? null;
const to_state = payload.to_state ?? null;
const transition = payload.transition ?? null;

// 4) Canonical timestamp: prefer event.event_ts; fallback to created_at; then now()
const timestamp =
  event.event_ts ??
  event.created_at ??
  new Date().toISOString();

// 5) Artifact identity: prefer event row, fallback to payload (belt + suspenders)
const workspace_id = event.workspace_id ?? payload.workspace_id ?? null;
const artifact_id = event.artifact_id ?? payload.artifact_id ?? null;
const artifact_type = payload.artifact_type ?? "project";

// 6) Return the required envelope
return [
  {
    json: {
      ok: true,
      gw_action: "artifact.promote",
      workspace_id,
      artifact_type,
      artifact_id,

      event_id: event.event_id ?? null,
      operation: "PROMOTE",
      from_state,
      to_state,
      transition,
      timestamp,

      data: { event },
    },
  },
];

// NQxb_Artifact_Promote_v1__QPM_Query_Children
// Purpose: Query child artifacts for QPM validation
// - For seed_to_sapling: count journal children
// - For sapling_to_tree: count execution anatomy children (branch, limb, leaf)
//
// QPM PHASE 2 (2026-02-01)
// This node prepares queries but actual DB calls happen in separate Supabase nodes
// Output includes the request context plus query parameters for child lookups

const input = $json;

const transition = (input.transition ?? "").toString().trim();
const artifactId = input.artifact_id ?? null;
const workspaceId = input.gw_workspace_id ?? null;

// Pass through with QPM query context
return [{
  json: {
    ...input,
    _qpm_context: {
      transition,
      artifact_id: artifactId,
      workspace_id: workspaceId,
      needs_journal_check: transition === "seed_to_sapling",
      needs_execution_check: transition === "sapling_to_tree",
    }
  }
}];

// NQxb_Artifact_Promote_v1__QPM_Validate_Rules
// Purpose: Enforce QPM lifecycle transition validation rules
// T87: Enhanced error hints for developer ergonomics.
//
// QPM PHASE 2 RULES:
// 1. seed_to_sapling: Requires summary OR linked journal child
// 2. sapling_to_tree: Requires execution anatomy (branch or leaf child)
// 3. tree_to_archive: No validation (always pass)

const input = $json;

const transition = (input.transition ?? "").toString().trim();
const summary = input._spine_summary ?? null;
const summaryTrimmed = (typeof summary === "string") ? summary.trim() : "";

const journalCount = input.journal_count;
const executionCount = input.execution_count;

if (typeof journalCount !== 'number') {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "JOURNAL_COUNT_UNAVAILABLE",
        message: "journal_count missing from upstream chain.",
        details: { journal_count: journalCount }
      }
    }
  }];
}

if (typeof executionCount !== 'number') {
  return [{
    json: {
      ...input,
      ok: false,
      _gw_route: "error",
      error: {
        code: "EXECUTION_COUNT_UNAVAILABLE",
        message: "execution_count missing from upstream chain.",
        details: { execution_count: executionCount }
      }
    }
  }];
}

if (transition === "seed_to_sapling") {
  const hasSummary = summaryTrimmed.length > 0;
  const hasJournalChild = journalCount > 0;

  if (!hasSummary && !hasJournalChild) {
    return [{
      json: {
        ...input,
        ok: false,
        _gw_route: "error",
        error: {
          code: "PROMOTION_BLOCKED_SEED_NOT_READY",
          message: "Seed \u2192 Sapling requires summary or linked journal",
          details: {
            artifact_id: input.artifact_id,
            has_summary: hasSummary,
            journal_child_count: journalCount,
            rule: "summary OR journal child required",
            hint: "Either update the project summary (via artifact.update with summary field) or create a journal with parent_artifact_id pointing to this project."
          }
        }
      }
    }];
  }
}

if (transition === "sapling_to_tree") {
  const hasExecutionAnatomy = executionCount > 0;

  if (!hasExecutionAnatomy) {
    return [{
      json: {
        ...input,
        ok: false,
        _gw_route: "error",
        error: {
          code: "PROMOTION_BLOCKED_NO_ANATOMY",
          message: "Sapling \u2192 Tree requires execution anatomy (branch or leaf)",
          details: {
            artifact_id: input.artifact_id,
            execution_child_count: executionCount,
            rule: "branch or leaf child required",
            hint: "Create at least one branch or leaf artifact with parent_artifact_id pointing to this project before promoting to tree."
          }
        }
      }
    }];
  }
}

return [{
  json: {
    ...input,
    ok: true,
    _gw_route: input._gw_route ?? "ok",
    _qpm_validated: {
      transition,
      summary_present: summaryTrimmed.length > 0,
      journal_child_count: journalCount,
      execution_child_count: executionCount
    }
  }
}];

// NQxb_Artifact_Promote_v1__QPM_Attach_Journal_Count
// Counts journal children from HTTP Request response items.
// Sequential chain: Prepare \u2192 JournalHTTP \u2192 this \u2192 ExecHTTP \u2192 ...
//
// HTTP Request returns N items (one per matching artifact).
// alwaysOutputData guarantees at least 1 item on empty result.
// Count = items with valid artifact_id.

const context = $node["NQxb_Artifact_Promote_v1__QPM_Prepare_Child_Queries"].json;
const items = $input.all();
const journal_count = items.filter(i => i.json?.artifact_id).length;

if (typeof journal_count !== 'number' || !Number.isFinite(journal_count)) {
  return [{
    json: {
      ...context,
      ok: false,
      _gw_route: "error",
      error: {
        code: "JOURNAL_COUNT_UNAVAILABLE",
        message: "Could not determine journal child count from HTTP response.",
        details: { item_count: items.length }
      }
    }
  }];
}

return [{
  json: {
    ...context,
    journal_count
  }
}];

// NQxb_Artifact_Promote_v1__QPM_Attach_Execution_Count
// Counts execution children from HTTP Request response items.
// Sequential chain: ... \u2192 AttachJournal \u2192 ExecHTTP \u2192 this \u2192 Validate
//
// HTTP Request returns N items (one per matching artifact).
// alwaysOutputData guarantees at least 1 item on empty result.
// Count = items with valid artifact_id.

const context = $node["NQxb_Artifact_Promote_v1__QPM_Attach_Journal_Count"].json;
const items = $input.all();
const execution_count = items.filter(i => i.json?.artifact_id).length;

if (typeof execution_count !== 'number' || !Number.isFinite(execution_count)) {
  return [{
    json: {
      ...context,
      ok: false,
      _gw_route: "error",
      error: {
        code: "EXECUTION_COUNT_UNAVAILABLE",
        message: "Could not determine execution child count from HTTP response.",
        details: { item_count: items.length }
      }
    }
  }];
}

return [{
  json: {
    ...context,
    execution_count
  }
}];
